import type * as DMMF from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

export function scalarTypeToTs(prismaType: string): string {
  return PRISMA_SCALAR_TO_TS[prismaType] ?? 'unknown'
}

/**
 * Returns the TypeScript type string for a DMMF field, including list notation.
 * Relation fields (kind `object`) use the related model name directly.
 */
export function fieldTypeToTs(field: DMMF.Field): string {
  let baseType: string
  switch (field.kind) {
    case 'scalar':
      baseType = scalarTypeToTs(field.type)
      break
    case 'enum':
    case 'object':
      baseType = field.type
      break
    case 'unsupported':
    default:
      baseType = 'unknown'
  }
  return field.isList ? `${baseType}[]` : baseType
}

/**
 * Returns true when a field's default value is a database-generated function
 * (e.g. `autoincrement()`, `uuid()`, `cuid()`, `now()`), meaning the caller
 * does not provide this value on create.
 */
export function isAutoGeneratedDefault(field: DMMF.Field): boolean {
  return (
    field.hasDefaultValue &&
    typeof field.default === 'object' &&
    field.default !== null &&
    !Array.isArray(field.default) &&
    'name' in field.default
  )
}

