import type * as DMMF from '@prisma/dmmf'

import { fieldTypeToTs, isAutoGeneratedDefault } from './type-mapper'

/** Lowercases the first character of a string (PascalCase → camelCase). */
function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Converts a model name to a lowercase URL path segment.
 * e.g. `BlogPost` → `blogpost`.
 */
function toUrlPath(modelName: string): string {
  return modelName.toLowerCase()
}

/** Returns only the scalar and enum fields of a model (excludes relations and unsupported). */
function scalarAndEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
}

/** Collects the names of all uniquely-identifying fields (id + unique). */
function uniqueFieldNames(model: DMMF.Model): Set<string> {
  const names = new Set<string>()
  for (const field of model.fields) {
    if (field.isId || field.isUnique) names.add(field.name)
  }
  for (const group of model.uniqueFields) {
    for (const name of group) names.add(name)
  }
  return names
}

function renderEnumType(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}\n`
}

function renderModelInterface(model: DMMF.Model): string {
  const lines = [`export interface ${model.name} {`]
  for (const field of model.fields) {
    if (field.kind === 'unsupported') continue
    const tsType = fieldTypeToTs(field)
    // Relations are always optional since they are not loaded by default.
    const optional = !field.isRequired || field.kind === 'object' ? '?' : ''
    const nullable = !field.isRequired ? ' | null' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}${nullable}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function renderCreateInput(model: DMMF.Model): string {
  const lines = [`export interface ${model.name}CreateInput {`]
  for (const field of scalarAndEnumFields(model)) {
    if (field.isReadOnly || field.isGenerated) continue
    // Skip IDs whose value is produced by the database (e.g. autoincrement, uuid).
    if (field.isId && isAutoGeneratedDefault(field)) continue
    const tsType = fieldTypeToTs(field)
    const optional = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function renderUpdateInput(model: DMMF.Model): string {
  const lines = [`export interface ${model.name}UpdateInput {`]
  for (const field of scalarAndEnumFields(model)) {
    if (field.isReadOnly || field.isGenerated || field.isId) continue
    lines.push(`  ${field.name}?: ${fieldTypeToTs(field)}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function renderWhereUniqueInput(model: DMMF.Model): string {
  const unique = uniqueFieldNames(model)
  const lines = [`export interface ${model.name}WhereUniqueInput {`]
  for (const field of scalarAndEnumFields(model)) {
    if (!unique.has(field.name)) continue
    lines.push(`  ${field.name}?: ${fieldTypeToTs(field)}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function renderWhereInput(model: DMMF.Model): string {
  const lines = [`export interface ${model.name}WhereInput {`]
  for (const field of scalarAndEnumFields(model)) {
    lines.push(`  ${field.name}?: ${fieldTypeToTs(field)}`)
  }
  lines.push('}')
  return lines.join('\n')
}

function renderModelClient(model: DMMF.Model): string {
  const n = model.name
  const urlPath = toUrlPath(n)

  return `\
export class ${n}RestClient {
  readonly #baseUrl: string
  readonly #fetch: typeof globalThis.fetch

  constructor(baseUrl: string, fetchFn: typeof globalThis.fetch) {
    this.#baseUrl = baseUrl
    this.#fetch = fetchFn
  }

  async findMany(params?: {
    where?: ${n}WhereInput
    skip?: number
    take?: number
    orderBy?: Partial<Record<keyof ${n}WhereInput, 'asc' | 'desc'>>
  }): Promise<${n}[]> {
    const url = new URL(\`\${this.#baseUrl}/${urlPath}\`)
    if (params?.where != null) url.searchParams.set('where', JSON.stringify(params.where))
    if (params?.skip != null) url.searchParams.set('skip', String(params.skip))
    if (params?.take != null) url.searchParams.set('take', String(params.take))
    if (params?.orderBy != null) url.searchParams.set('orderBy', JSON.stringify(params.orderBy))
    const response = await this.#fetch(url.toString())
    if (!response.ok) {
      throw new Error(\`findMany ${n} failed with HTTP \${response.status}\`)
    }
    return response.json() as Promise<${n}[]>
  }

  async findUnique(where: ${n}WhereUniqueInput): Promise<${n} | null> {
    const url = new URL(\`\${this.#baseUrl}/${urlPath}/unique\`)
    url.searchParams.set('where', JSON.stringify(where))
    const response = await this.#fetch(url.toString())
    if (response.status === 404) return null
    if (!response.ok) {
      throw new Error(\`findUnique ${n} failed with HTTP \${response.status}\`)
    }
    return response.json() as Promise<${n}>
  }

  async create(data: ${n}CreateInput): Promise<${n}> {
    const response = await this.#fetch(\`\${this.#baseUrl}/${urlPath}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) {
      throw new Error(\`create ${n} failed with HTTP \${response.status}\`)
    }
    return response.json() as Promise<${n}>
  }

  async update(where: ${n}WhereUniqueInput, data: ${n}UpdateInput): Promise<${n}> {
    const response = await this.#fetch(\`\${this.#baseUrl}/${urlPath}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ where, data }),
    })
    if (!response.ok) {
      throw new Error(\`update ${n} failed with HTTP \${response.status}\`)
    }
    return response.json() as Promise<${n}>
  }

  async delete(where: ${n}WhereUniqueInput): Promise<${n}> {
    const response = await this.#fetch(\`\${this.#baseUrl}/${urlPath}\`, {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(where),
    })
    if (!response.ok) {
      throw new Error(\`delete ${n} failed with HTTP \${response.status}\`)
    }
    return response.json() as Promise<${n}>
  }
}`
}

function renderPrismaRestClient(models: readonly DMMF.Model[]): string {
  const lines = ['export class PrismaRestClient {']
  for (const model of models) {
    lines.push(`  readonly ${toCamelCase(model.name)}: ${model.name}RestClient`)
  }
  lines.push('')
  lines.push('  constructor(config: { baseUrl: string; fetch?: typeof globalThis.fetch }) {')
  lines.push('    const fetchFn = config.fetch ?? globalThis.fetch')
  for (const model of models) {
    lines.push(`    this.${toCamelCase(model.name)} = new ${model.name}RestClient(config.baseUrl, fetchFn)`)
  }
  lines.push('  }')
  lines.push('}')
  return lines.join('\n')
}

/** Renders the complete generated REST client source as a TypeScript string. */
export function renderGeneratedClient(dmmf: DMMF.Document): string {
  const sections: string[] = []

  sections.push('// Code generated by @prisma/rest-client-generator. Do not edit.')
  sections.push('')

  if (dmmf.datamodel.enums.length > 0) {
    sections.push('// ---- Enums ----')
    sections.push('')
    for (const enumDef of dmmf.datamodel.enums) {
      sections.push(renderEnumType(enumDef))
    }
  }

  if (dmmf.datamodel.models.length > 0) {
    sections.push('// ---- Model interfaces and input types ----')
    sections.push('')
    for (const model of dmmf.datamodel.models) {
      sections.push(renderModelInterface(model))
      sections.push('')
      sections.push(renderCreateInput(model))
      sections.push('')
      sections.push(renderUpdateInput(model))
      sections.push('')
      sections.push(renderWhereUniqueInput(model))
      sections.push('')
      sections.push(renderWhereInput(model))
      sections.push('')
    }

    sections.push('// ---- Per-model REST clients ----')
    sections.push('')
    for (const model of dmmf.datamodel.models) {
      sections.push(renderModelClient(model))
      sections.push('')
    }

    sections.push('// ---- Top-level client ----')
    sections.push('')
    sections.push(renderPrismaRestClient(dmmf.datamodel.models))
    sections.push('')
  }

  return sections.join('\n')
}

