import type { GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { renderGeneratedClient } from './renderer'

/**
 * Runs the REST client generator: reads the DMMF from `options`, renders
 * TypeScript source, and writes `index.ts` into the configured output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = parseEnvValue(options.generator.output!)
  await fs.mkdir(outputDir, { recursive: true })

  const code = renderGeneratedClient(options.dmmf)
  await fs.writeFile(path.join(outputDir, 'index.ts'), code, 'utf-8')
