import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { renderGeneratedClient } from './renderer'
import { fieldTypeToTs, isAutoGeneratedDefault, scalarTypeToTs } from './type-mapper'

// ---------------------------------------------------------------------------
// Minimal DMMF fixtures
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: true,
    isReadOnly: false,
    type: 'Int',
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as DMMF.Model
}

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: { models, enums, types: [], indexes: [] },
    schema: { inputObjectTypes: {}, outputObjectTypes: { model: [], prisma: [] }, enumTypes: { prisma: [] }, fieldRefTypes: {} },
    mappings: { modelOperations: [], otherOperations: { read: [], write: [] } },
  } as unknown as DMMF.Document
}

// ---------------------------------------------------------------------------
// scalarTypeToTs
// ---------------------------------------------------------------------------

describe('scalarTypeToTs', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Uint8Array'],
  ])('maps %s → %s', (prismaType, expected) => {
    expect(scalarTypeToTs(prismaType)).toBe(expected)
  })

  test('returns unknown for unrecognised scalar', () => {
    expect(scalarTypeToTs('VeryCustomType')).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// fieldTypeToTs
// ---------------------------------------------------------------------------

describe('fieldTypeToTs', () => {
  test('scalar field', () => {
    expect(fieldTypeToTs(makeField({ kind: 'scalar', type: 'String' }))).toBe('string')
  })

  test('list scalar field', () => {
    expect(fieldTypeToTs(makeField({ kind: 'scalar', type: 'Int', isList: true }))).toBe('number[]')
  })

  test('enum field', () => {
    expect(fieldTypeToTs(makeField({ kind: 'enum', type: 'Role' } as Partial<DMMF.Field>))).toBe('Role')
  })

  test('object (relation) field', () => {
    expect(fieldTypeToTs(makeField({ kind: 'object', type: 'Post' } as Partial<DMMF.Field>))).toBe('Post')
  })

  test('unsupported field', () => {
    expect(fieldTypeToTs(makeField({ kind: 'unsupported', type: 'geometry' } as Partial<DMMF.Field>))).toBe('unknown')
  })
})

// ---------------------------------------------------------------------------
// isAutoGeneratedDefault
// ---------------------------------------------------------------------------

describe('isAutoGeneratedDefault', () => {
  test('true for autoincrement', () => {
    const field = makeField({ hasDefaultValue: true, default: { name: 'autoincrement', args: [] } })
    expect(isAutoGeneratedDefault(field)).toBe(true)
  })

  test('true for uuid()', () => {
    const field = makeField({ hasDefaultValue: true, default: { name: 'uuid', args: [] } })
    expect(isAutoGeneratedDefault(field)).toBe(true)
  })

  test('true for now()', () => {
    const field = makeField({ hasDefaultValue: true, default: { name: 'now', args: [] } })
    expect(isAutoGeneratedDefault(field)).toBe(true)
  })

  test('false for static scalar default', () => {
    const field = makeField({ hasDefaultValue: true, default: 'active' })
    expect(isAutoGeneratedDefault(field)).toBe(false)
  })

  test('false when hasDefaultValue is false', () => {
    const field = makeField({ hasDefaultValue: false })
    expect(isAutoGeneratedDefault(field)).toBe(false)
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – header
// ---------------------------------------------------------------------------

describe('renderGeneratedClient header', () => {
  test('starts with the do-not-edit banner', () => {
    const output = renderGeneratedClient(makeDmmf([]))
    expect(output).toContain('// Code generated by @prisma/rest-client-generator. Do not edit.')
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – enums
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – enums', () => {
  const dmmf = makeDmmf([], [
    { name: 'Role', values: [{ name: 'ADMIN', dbName: null }, { name: 'USER', dbName: null }] },
  ] as DMMF.DatamodelEnum[])

  test('renders enum as a TypeScript union type', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain("export type Role = 'ADMIN' | 'USER'")
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – model interface
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – model interface', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
    makeField({ name: 'email', kind: 'scalar', type: 'String', isId: false, isUnique: true }),
    makeField({ name: 'createdAt', kind: 'scalar', type: 'DateTime', isId: false, hasDefaultValue: true, default: { name: 'now', args: [] } }),
    // optional field
    makeField({ name: 'bio', kind: 'scalar', type: 'String', isId: false, isRequired: false }),
    // relation
    makeField({ name: 'posts', kind: 'object', type: 'Post', isId: false, isList: true, isRequired: false } as Partial<DMMF.Field>),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('generates User interface', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('export interface User {')
  })

  test('required field has no optional marker', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/name: string/)
  })

  test('optional field gets ? marker and | null', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/bio\?: string \| null/)
  })

  test('relation field is always optional', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/posts\?: Post\[\]/)
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – CreateInput
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – CreateInput', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true, hasDefaultValue: true, default: { name: 'autoincrement', args: [] } }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
    makeField({ name: 'email', kind: 'scalar', type: 'String', isId: false, isUnique: true }),
    makeField({ name: 'createdAt', kind: 'scalar', type: 'DateTime', isId: false, hasDefaultValue: true, default: { name: 'now', args: [] } }),
    makeField({ name: 'readOnlyField', kind: 'scalar', type: 'String', isId: false, isReadOnly: true }),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('generates UserCreateInput interface', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('export interface UserCreateInput {')
  })

  test('auto-generated ID is excluded', () => {
    const output = renderGeneratedClient(dmmf)
    // id should not appear in CreateInput (it's autoincrement)
    const createInputSection = output.slice(output.indexOf('export interface UserCreateInput {'))
    const closingBrace = createInputSection.indexOf('}')
    const createInputBody = createInputSection.slice(0, closingBrace)
    expect(createInputBody).not.toMatch(/\bid:/)
  })

  test('required field without default is required in CreateInput', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/name: string/)
  })

  test('field with default is optional in CreateInput', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/createdAt\?: Date/)
  })

  test('readOnly field is excluded from CreateInput', () => {
    const output = renderGeneratedClient(dmmf)
    const createInputSection = output.slice(output.indexOf('export interface UserCreateInput {'))
    const closingBrace = createInputSection.indexOf('}')
    expect(createInputSection.slice(0, closingBrace)).not.toContain('readOnlyField')
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – UpdateInput
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – UpdateInput', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
    makeField({ name: 'email', kind: 'scalar', type: 'String', isId: false }),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('generates UserUpdateInput interface', () => {
    expect(renderGeneratedClient(dmmf)).toContain('export interface UserUpdateInput {')
  })

  test('id field is excluded', () => {
    const output = renderGeneratedClient(dmmf)
    const section = output.slice(output.indexOf('export interface UserUpdateInput {'))
    expect(section.slice(0, section.indexOf('}'))).not.toMatch(/\bid\b/)
  })

  test('all remaining fields are optional', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/name\?: string/)
    expect(output).toMatch(/email\?: string/)
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – WhereUniqueInput
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – WhereUniqueInput', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true }),
    makeField({ name: 'email', kind: 'scalar', type: 'String', isId: false, isUnique: true }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('generates UserWhereUniqueInput interface', () => {
    expect(renderGeneratedClient(dmmf)).toContain('export interface UserWhereUniqueInput {')
  })

  test('includes id and unique fields', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toMatch(/id\?: number/)
    expect(output).toMatch(/email\?: string/)
  })

  test('excludes non-unique fields', () => {
    const output = renderGeneratedClient(dmmf)
    const section = output.slice(output.indexOf('export interface UserWhereUniqueInput {'))
    expect(section.slice(0, section.indexOf('}'))).not.toContain('name?')
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – WhereInput
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – WhereInput', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('all scalar fields appear as optional filters', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('export interface UserWhereInput {')
    expect(output).toMatch(/id\?: number/)
    expect(output).toMatch(/name\?: string/)
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – RestClient class
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – RestClient class', () => {
  const fields: DMMF.Field[] = [
    makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true }),
    makeField({ name: 'name', kind: 'scalar', type: 'String', isId: false }),
  ]
  const dmmf = makeDmmf([makeModel('User', fields)])

  test('generates UserRestClient class', () => {
    expect(renderGeneratedClient(dmmf)).toContain('export class UserRestClient {')
  })

  test('uses native private fields', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('readonly #baseUrl')
    expect(output).toContain('readonly #fetch')
  })

  test('generates all five CRUD methods', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  test('findMany URL uses lowercase model name', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('`${this.#baseUrl}/user`')
  })

  test('findUnique URL includes /unique suffix', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('`${this.#baseUrl}/user/unique`')
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – PrismaRestClient
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – PrismaRestClient', () => {
  const userFields: DMMF.Field[] = [makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true })]
  const postFields: DMMF.Field[] = [makeField({ name: 'id', kind: 'scalar', type: 'Int', isId: true })]
  const dmmf = makeDmmf([makeModel('User', userFields), makeModel('Post', postFields)])

  test('generates PrismaRestClient class', () => {
    expect(renderGeneratedClient(dmmf)).toContain('export class PrismaRestClient {')
  })

  test('has camelCase properties for each model', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('readonly user: UserRestClient')
    expect(output).toContain('readonly post: PostRestClient')
  })

  test('constructor accepts baseUrl and optional fetch', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('constructor(config: { baseUrl: string; fetch?: typeof globalThis.fetch })')
  })

  test('instantiates each sub-client in constructor', () => {
    const output = renderGeneratedClient(dmmf)
    expect(output).toContain('this.user = new UserRestClient(config.baseUrl, fetchFn)')
    expect(output).toContain('this.post = new PostRestClient(config.baseUrl, fetchFn)')
  })
})

// ---------------------------------------------------------------------------
// renderGeneratedClient – empty schema
// ---------------------------------------------------------------------------

describe('renderGeneratedClient – empty schema', () => {
  test('produces only the header for an empty DMMF', () => {
    const output = renderGeneratedClient(makeDmmf([]))
    expect(output.trim()).toBe('// Code generated by @prisma/rest-client-generator. Do not edit.')
  })
})

